const sendgridApiKey = 'YOUR_SENDGRID_API_KEY';
const stripeApiKey = 'YOUR_STRIPE_API_KEY';

async function sendEmail(to, subject, text) {
    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${sendgridApiKey}`,
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            personalizations: [{ to: [{ email: to }] }],
            from: { email: 'your-email@example.com' },
            subject: subject,
            content: [{ type: 'text/plain', value: text }],
        }),
    });
    if (!response.ok) {
        throw new Error(`SendGrid Error: ${response.statusText}`);
    }
    return response.json();
}

async function createPayment(amount, currency) {
    const response = await fetch('https://api.stripe.com/v1/charges', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${stripeApiKey}`,
            'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
            amount: amount,
            currency: currency,
            source: 'tok_visa', // Replace with actual token from client
            description: 'Charge for service',
        }),
    });
    if (!response.ok) {
        throw new Error(`Stripe Error: ${response.statusText}`);
    }
    return response.json();
}

addEventListener('fetch', event => {
    event.respondWith(handleRequest(event.request));
});

async function handleRequest(request) {
    try {
        const { method, url } = request;
        if (method === 'POST' && url.endsWith('/send-email')) {
            const { to, subject, text } = await request.json();
            const emailResponse = await sendEmail(to, subject, text);
            return new Response(JSON.stringify(emailResponse), { status: 200 });
        } else if (method === 'POST' && url.endsWith('/create-payment')) {
            const { amount, currency } = await request.json();
            const paymentResponse = await createPayment(amount, currency);
            return new Response(JSON.stringify(paymentResponse), { status: 200 });
        } else {
            return new Response('Not Found', { status: 404 });
        }
    } catch (error) {
        return new Response(error.message, { status: 500 });
    }
}